// Code node: Parse alle gegevens uit NWWI aanvraagbevestiging email
const emailBody = items[0].json.textHtml;

// === 1. ADRES VAN HET OBJECT ===
const startText = 'Er is voor u een aanvraag gedaan voor het volgende object:<br />';
const startIndex = emailBody.indexOf(startText);
if (startIndex === -1) throw new Error('Kan het startpunt van het adres niet vinden');
const addressStart = startIndex + startText.length;
const addressEnd = emailBody.indexOf('.', addressStart);
if (addressEnd === -1) throw new Error('Kan het eindpunt van het adres niet vinden');
const address = emailBody.substring(addressStart, addressEnd).trim();

// === 2. HELPER: Parse een tabel-sectie op basis van header tekst ===
function parseTableSection(html, headerText) {
  const result = {};
  const headerIndex = html.indexOf(headerText);
  if (headerIndex === -1) return result;

  // Zoek de <table> die bij deze header hoort
  const tableStart = html.lastIndexOf('<table>', headerIndex);
  const tableEnd = html.indexOf('</table>', headerIndex);
  if (tableStart === -1 || tableEnd === -1) return result;

  const tableHtml = html.substring(tableStart, tableEnd + 8);

  // Parse alle rijen met <td> paren
  const rowRegex = /<tr><td[^>]*>([^<]*)<\/td><td>([^<]*(?:<br\s*\/?>)?[^<]*)<\/td><\/tr>/gi;
  let match;
  while ((match = rowRegex.exec(tableHtml)) !== null) {
    const key = match[1].replace(/:$/, '').trim();
    const value = match[2].replace(/<br\s*\/?>/gi, '').trim();
    if (key && value) {
      result[key] = value;
    }
  }
  return result;
}

// === 3. PARSE ALLE SECTIES ===
const opdrachtgever = parseTableSection(emailBody, 'Gegevens opdrachtgever:');
const opdrachtverstrekker = parseTableSection(emailBody, 'Gegevens opdrachtverstrekker:');
const bijzonderheden = parseTableSection(emailBody, 'Bijzonderheden:');
// === 5. PARSE POSTCODE EN PLAATS UIT ADRES ===
// Adres formaat: "Irenestraat 10 , 3238XT ZWARTEWAAL"
const postcodeMatch = address.match(/\b(\d{4}\s*[A-Za-z]{2})\s+(.+)$/);
const postcode = postcodeMatch ? postcodeMatch[1].replace(/\s/g, '').toUpperCase() : '';
const plaats = postcodeMatch ? postcodeMatch[2].trim() : '';

// === 4. RETURN ALLES ===
return [{
  json: {
    ...items[0].json,
    address: address,
    postcode: postcode,
    plaats: plaats,

    // Opdrachtgever (de klant)
    opdrachtgever: {
      naam: opdrachtgever['Opdrachtgever'] || '',
      adres: opdrachtgever['Adres'] || '',
      postcodeEnPlaats: opdrachtgever['Postcode en plaats'] || '',
      telefoon: opdrachtgever['Telefoon'] || '',
      email: opdrachtgever['E-mail'] || '',
    },

    // Opdrachtverstrekker (de hypotheekadviseur)
    opdrachtverstrekker: {
      bedrijfsnaam: opdrachtverstrekker['Bedrijfsnaam'] || '',
      contactpersoon: opdrachtverstrekker['Contactpersoon'] || '',
      adres: opdrachtverstrekker['Adres'] || '',
      postcodeEnPlaats: opdrachtverstrekker['Postcode en plaats'] || '',
      telefoon: opdrachtverstrekker['Telefoon'] || '',
      email: opdrachtverstrekker['E-mail'] || '',
    },

    // Bijzonderheden
    bijzonderheden: {
      doelTaxatie: bijzonderheden['Doel taxatie'] || '',
      typeRapport: bijzonderheden['Type rapport'] || '',
      referentie: bijzonderheden['Referentie'] || '',
      selectie: bijzonderheden['Selectie'] || '',
      opmerkingen: bijzonderheden['Opmerkingen bij aanvraag'] || '',
      verbouwing: bijzonderheden['Verbouwing'] || '',
    },
  }
}];

// N8N code node - direct bruikbaar
const addressString = items[0].json.address;

if (!addressString) {
    throw new Error('Geen adres gevonden in input');
}

// Parse postcode (4 cijfers + 2 letters)
const postcodeMatch = addressString.match(/\b(\d{4})\s*([A-Za-z]{2})\b/);
if (!postcodeMatch) {
    throw new Error('Geen geldige postcode gevonden in adres');
}
const cleanPostcode = (postcodeMatch[1] + postcodeMatch[2]).toUpperCase();

// Parse huisnummer
const huisnummerMatch = addressString.match(/\b(\d+(?:[A-Za-z])?)\b/);
if (!huisnummerMatch) {
    throw new Error('Geen geldig huisnummer gevonden in adres');
}
const huisnummer = huisnummerMatch[1];

// Return in correct format voor N8N
return [{
    json: {
        postcode: cleanPostcode,
        huisnummer: huisnummer
    }
}];

const data = $('Code').item.json;
const projectId = $('Project aanmaken devree-platform').item.json.project.id;

return [{
  json: {
    action: "create",
    title: `Taxatie acceptatie: ${data.address}`,
    description: [
      "NWWI taxatieaanvraag ontvangen.",
      "",
      `Opdrachtgever: ${data.opdrachtgever.naam}`,
      `Telefoon: ${data.opdrachtgever.telefoon}`,
      `Email: ${data.opdrachtgever.email}`,
      "",
      `Opdrachtverstrekker: ${data.opdrachtverstrekker.bedrijfsnaam}`,
      `Opmerkingen: ${data.bijzonderheden.opmerkingen}`
    ].join("\n"),
    projectId: projectId,
    priority: "hoog",
    category: "taxatie",
    assigneeEmail: "info@devreemakelaardij.nl"
  }
}];
